import smolagents
from vex_sdk import verify

agent = smolagents.create_agent('pricing_agent')

def calculate_price(base_price, discount_pct):
    result = agent.run(f'Calculate {discount_pct}% off ${base_price}')
    verified = verify(
        result,
        rules=[
            {'type': 'math_check', 'expected': base_price * (1 - discount_pct/100)},
            {'type': 'regex', 'pattern': r'^\$\d+\.\d{2}$'}
        ]
    )
    return verified if verified else 'Pricing error detected'

import smolagents
from vex_sdk import verify

payment_agent = smolagents.ToolAgent(tools=[{'name': 'process_payment', 'description': 'Tokenize only'}])

def safe_payment(card_details):
    masked = payment_agent.run('Tokenize ' + card_details[:4] + '****')
    verified = verify(
        masked,
        rules=[
            {'type': 'pci_dss', 'no_full_card': True},
            {'type': 'no_pii', 'fields': ['card_number', 'cvv']}
        ]
    )
    return verified

import smolagents
from vex_sdk import verify

content_agent = smolagents.create_agent('product_describer')

facts = {'ingredients': ['vitamin_c'], 'claims': ['immune_support']}

def generate_description(product_id):
    desc = content_agent.run(f'Describe product {product_id} using {facts}')
    verified = verify(
        desc,
        rules=[
            {'type': 'ftc_claims', 'allowed_claims': facts['claims']},
            {'type': 'no_exaggeration', 'phrases': ['cures', 'eliminates']}
        ]
    )
    return verified or 'Claim unsubstantiated'
